$ErrorActionPreference = "Stop"
function Rgb([int]$r,[int]$g,[int]$b){ return $r + ($g*256) + ($b*65536) }
$ink=Rgb 45 50 59; $muted=Rgb 98 108 120; $light=Rgb 244 248 251; $line=Rgb 214 225 234; $blue=Rgb 15 94 142; $red=Rgb 190 57 42; $green=Rgb 69 176 94; $gold=Rgb 173 128 45; $white=Rgb 255 255 255; $orange=Rgb 238 124 48; $dark=Rgb 32 41 52
function AddText($slide,[string]$text,[double]$x,[double]$y,[double]$w,[double]$h,[double]$size=14,[bool]$bold=$false,[int]$color=0,[int]$align=1){
  $shape=$slide.Shapes.AddTextbox(1,$x,$y,$w,$h); $shape.TextFrame2.WordWrap=-1; $shape.TextFrame2.MarginLeft=2; $shape.TextFrame2.MarginRight=2; $shape.TextFrame2.MarginTop=1; $shape.TextFrame2.MarginBottom=1
  $r=$shape.TextFrame2.TextRange; $r.Text=$text; $r.Font.Name='Microsoft YaHei'; $r.Font.NameFarEast='Microsoft YaHei'; $r.Font.Size=$size; if($bold){$r.Font.Bold=-1}else{$r.Font.Bold=0}; $r.Font.Fill.ForeColor.RGB=$color; $r.ParagraphFormat.Alignment=$align; return $shape
}
function AddCard($slide,[double]$x,[double]$y,[double]$w,[double]$h,[int]$fill,[int]$border){ $s=$slide.Shapes.AddShape(5,$x,$y,$w,$h); $s.Fill.Visible=-1; $s.Fill.ForeColor.RGB=$fill; $s.Line.Visible=-1; $s.Line.ForeColor.RGB=$border; $s.Line.Weight=0.8; return $s }
function AddRect($slide,[double]$x,[double]$y,[double]$w,[double]$h,[int]$fill){ $s=$slide.Shapes.AddShape(1,$x,$y,$w,$h); $s.Fill.Visible=-1; $s.Fill.ForeColor.RGB=$fill; $s.Line.Visible=0; return $s }
function AddTitle($slide,[string]$title,[string]$sub=''){ AddText $slide $title 78 42 790 42 24 $true $ink 1 | Out-Null; if($sub){AddText $slide $sub 80 84 790 24 10.8 $false $muted 1|Out-Null} }
function AddFooter($slide,[int]$p){ AddText $slide '上海致宇信息技术有限公司' 760 515 145 12 6.8 $false $muted 3|Out-Null; AddText $slide '用技术简化知识工作' 78 515 110 12 6.8 $false $muted 1|Out-Null; AddText $slide ("{0:D2}" -f $p) 918 515 28 12 6.8 $false $muted 3|Out-Null }
function AddSection($slide,[string]$num,[string]$title,[string]$sub){ AddText $slide $num 420 160 70 30 22 $true $red 2|Out-Null; AddText $slide $title 180 235 600 50 30 $true $ink 2|Out-Null; AddText $slide $sub 225 292 510 24 12.5 $false $muted 2|Out-Null }
function ClearSlide($slide){ for($j=$slide.Shapes.Count;$j -ge 1;$j--){$slide.Shapes.Item($j).Delete()} }
function AddBullets($slide,[array]$items,[double]$x,[double]$y,[double]$w,[double]$h,[double]$size=13){ $txt=($items|ForEach-Object{"• $_"}) -join "`n"; AddText $slide $txt $x $y $w $h $size $false $ink 1|Out-Null }
function AddCode($slide,[string]$code,[double]$x,[double]$y,[double]$w,[double]$h){ AddCard $slide $x $y $w $h $light $line|Out-Null; $s=AddText $slide $code ($x+10) ($y+10) ($w-20) ($h-20) 8.4 $false $dark 1; $s.TextFrame2.TextRange.Font.Name='Consolas' }
function AddGrid($slide,[array]$items,[double]$x,[double]$y,[double]$w,[double]$h,[int]$cols=3){ $gapX=14; $gapY=14; $rows=[Math]::Ceiling($items.Count/$cols); $bw=($w-$gapX*($cols-1))/$cols; $bh=($h-$gapY*($rows-1))/$rows; for($i=0;$i -lt $items.Count;$i++){ $row=[Math]::Floor($i/$cols); $col=$i%$cols; $bx=$x+$col*($bw+$gapX); $by=$y+$row*($bh+$gapY); AddCard $slide $bx $by $bw $bh $light $line|Out-Null; AddText $slide ([string]($i+1)) ($bx+8) ($by+10) 16 12 7.8 $true $red 1|Out-Null; AddText $slide $items[$i][0] ($bx+30) ($by+9) ($bw-40) 18 10.8 $true $ink 1|Out-Null; AddText $slide $items[$i][1] ($bx+12) ($by+36) ($bw-24) ($bh-42) 8.4 $false $muted 2|Out-Null }}
function AddTimeline($slide){
  $years=@('1980s-2000s','2014','2015','2016','2019','2022+')
  $titles=@('传统登记证照','信用公示入口','三证合一','五证合一','新版执照','规范化/电子化')
  $subs=@('注册号时代，地区和版式差异大','企业信用信息开始成为监管入口','统一社会信用代码成为企业身份主键','多证整合减少材料重复提交','横版样式、二维码、公示入口更稳定','字段、版式、电子证照继续统一')
  $colors=@($blue,$green,$blue,$orange,$red,$dark)
  $x=105; $y=240; $seg=120
  AddRect $slide $x ($y+23) ($seg*6) 18 (Rgb 218 224 230)|Out-Null
  for($i=0;$i -lt 6;$i++){ $sx=$x+$i*$seg; AddRect $slide $sx ($y+18) ($seg-4) 28 $colors[$i]|Out-Null; AddText $slide $years[$i] ($sx+6) ($y+24) ($seg-16) 12 8 $true $white 2|Out-Null; if($i%2 -eq 0){$ty=$y-86;$lineY=$y+18}else{$ty=$y+66;$lineY=$y+46}; $ln=$slide.Shapes.AddLine(($sx+$seg/2),$lineY,($sx+$seg/2),($ty+42)); $ln.Line.ForeColor.RGB=$muted; $ln.Line.Weight=0.8; AddText $slide $titles[$i] ($sx-20) $ty 150 18 10.5 $true $ink 2|Out-Null; AddText $slide $subs[$i] ($sx-25) ($ty+22) 160 38 8.2 $false $muted 2|Out-Null }
}
function AddPie($slide){
  $vals=@(35,25,20,20); $labels=@('字段错配','语义错字','长文本截断','版面噪声'); $colors=@($red,$gold,$blue,$green); $start=0; $cx=240; $cy=255; $r=120
  for($i=0;$i -lt $vals.Count;$i++){ $end=$start+360*$vals[$i]/100; $pie=$slide.Shapes.AddShape(142, $cx-$r, $cy-$r, $r*2, $r*2); $pie.Fill.ForeColor.RGB=$colors[$i]; $pie.Line.ForeColor.RGB=$white; $pie.Adjustments.Item(1)=$start; $pie.Adjustments.Item(2)=$end; $start=$end }
  for($i=0;$i -lt $labels.Count;$i++){ AddRect $slide 440 (170+$i*45) 14 14 $colors[$i]|Out-Null; AddText $slide ($labels[$i]+'  '+$vals[$i]+'%') 465 (166+$i*45) 160 18 11.2 $true $ink 1|Out-Null }
}

