$s=$pres.Slides.Item(18); AddTitle $s '代码 3：大模型后处理不是乱改，而是被严格约束' 'prompt 明确要求只修复有依据的 OCR 错字，并且只输出 JSON。'; AddCode $s "严格规则：`n1. 只能修复 OCR 明显错字、字段粘连、标签混入、常见字符混淆。`n2. 不要编造 OCR 全文中没有依据的信息。`n3. 统一社会信用代码、日期、金额如果没有把握，不要修改。`n4. 经营范围可以根据营业执照常见语义修复明显错字，但必须保守。`n5. 只输出 JSON，不要输出解释性文字。" 95 145 520 220; AddBullets $s @('LLM 负责语义候选，不负责最终拍板','规则和权威库仍然是兜底','保留 actions，知道它改了什么、为什么改','低置信度修复应进入人工复核') 650 165 230 155 12; AddFooter $s 18
$s=$pres.Slides.Item(19); AddTitle $s '运行结果：这次图片链路确实经过了 OCR 和大模型' '摘要中能看到 OCR 模型、LLM 模型、耗时和结果保存路径。'; $metrics=@(@('OCR 模型','PaddleOCR-VL-1.6',$blue),@('大模型','claude-sonnet-4-6',$red),@('大模型耗时','14.256 秒',$green),@('自动修复字段','7 个',$gold)); for($i=0;$i -lt $metrics.Count;$i++){ $x=95+$i*185; AddCard $s $x 150 160 65 $light $line|Out-Null; AddText $s $metrics[$i][1] ($x+10) 163 140 18 12.5 $true $metrics[$i][2] 2|Out-Null; AddText $s $metrics[$i][0] ($x+10) 192 140 12 8.5 $false $muted 2|Out-Null}; AddCode $s "========== 运行摘要 ==========`n输入类型：图片`n输入路径：D:\OCR_Research\agent\data\188.jpg`nOCR 模型：PaddleOCR-VL-1.6`n调用模型：claude-sonnet-4-6`n大模型耗时：14.256 秒`n结果已保存：D:\OCR_Research\agent\outputs\license_image_agent_result.json" 135 260 700 150; AddFooter $s 19
$s=$pres.Slides.Item(20); AddTitle $s '修复结果示例：从 OCR 字段到可信字段' '讲这页时重点强调：修复动作保存在 repair_actions，不是静默覆盖。'; $heads=@('字段','修复前','修复后'); $xs=@(95,260,530); $ws=@(165,270,310); for($c=0;$c -lt 3;$c++){AddCard $s $xs[$c] 145 $ws[$c] 30 $blue $blue|Out-Null; AddText $s $heads[$c] ($xs[$c]+4) 153 ($ws[$c]-8) 12 8.8 $true $white 2|Out-Null}; $rows=@(@('统一社会信用代码','92440300MA5FPG0XXH','91110108306767909G'),@('类型','个体工商户','有限责任公司（自然人独资）'),@('法定代表人','薛丁川','刘福喜'),@('住所','深圳市宝安区...佛商大厦027','北京市海淀区中关村大街...405室')); for($r=0;$r -lt $rows.Count;$r++){for($c=0;$c -lt 3;$c++){ $y=175+$r*48; AddCard $s $xs[$c] $y $ws[$c] 48 $light $line|Out-Null; AddText $s $rows[$r][$c] ($xs[$c]+5) ($y+16) ($ws[$c]-10) 12 8.3 $false $ink 2|Out-Null }}; AddText $s '注意：这类修复后续最好接入行政区划库、企业信用公示数据做二次确认。' 120 420 710 22 13.5 $true $red 2|Out-Null; AddFooter $s 20
$s=$pres.Slides.Item(21); AddSection $s '05' '沉淀 Skill' '把一次 demo 变成可复用的方法'; AddFooter $s 21
$s=$pres.Slides.Item(22); AddTitle $s '业务 Skill：沉淀「营业执照怎么识别」' '不是一句空泛的总结，而是把字段、规则、修复策略写成下一次可用的工作手册。'; AddGrid $s @(@('字段清单','统一社会信用代码、名称、类型、负责人、资本、地址、经营范围等'),@('字段别名','法定代表人/经营者/负责人/执行事务合伙人'),@('校验规则','信用代码校验位、日期格式、金额格式'),@('修复策略','O/0、I/1、标签混入、字段粘连'),@('输出契约','final_fields、repair_actions、summary'),@('演示讲法','OCR 负责看见，Agent 负责可信')) 95 150 760 230 3; AddFooter $s 22
$s=$pres.Slides.Item(23); AddTitle $s '环境 Skill：沉淀「本地怎么跑起来」' '这部分对以后最有用：代理、证书、模型缓存、CPU 慢的问题，下次不用重新摸索。'; AddBullets $s @('conda 环境：company_tool','模型：PaddleOCR-VL-1.6，本地 CPU 可跑但耗时较长','代理：模型下载失败时配置 HTTP_PROXY / HTTPS_PROXY','证书：SSL_CERT_FILE 指向 certifi cacert.pem，避免 FileNotFoundError','API key：setx 后当前终端不生效，代码读取 Windows 用户环境变量兜底','默认参数：python app.py 即可演示，不要求现场输入长命令') 120 150 720 230 15; AddFooter $s 23
